UPDATE public.questions SET
  stimulus_text = 'The most common punctuation error that occurs in this type of writing is a comma splice.  A comma splice is a comma used incorrectly to separate two complete sentences without a conjunction. This is incorrect because a comma cannot be used in this way to join two complete sentences.  What is the main reason why this is a punctuation error? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
  question_text = 'The main reason why a comma splice is a punctuation error is that',
